SELECT 

FROM late_return lr
LEFT JOIN student s ON lr.student_no = s.student_no


        AND lr.id = #{id}


        AND lr.late_return_id = #{lateReturnId}


        AND lr.student_no = #{studentNo}


        AND lr.process_status = #{processStatus}


        AND lr.process_result = #{processResult}


        AND s.name LIKE CONCAT('%', #{studentName}, '%')


        AND s.college = #{college}


        AND s.dormitory = #{dormitory}


        AND s.dormitory LIKE CONCAT(#{dormitoryLike}, '%')


        AND lr.late_time >= #{startLateTime}


        AND lr.late_time <= #{endLateTime}




        AND lr.student_no IN

            #{studentNo}




        AND s.college IN

            #{college}




        AND s.dormitory IN

            #{dormitory}




        AND s.class_name IN

            #{className}




        AND (
            lr.process_result IN

                #{result}

            OR lr.process_result IS NULL
        )


ORDER BY lr.late_time DESC

SELECT 

FROM late_return lr
LEFT JOIN student s ON lr.student_no = s.student_no
WHERE lr.late_time BETWEEN #{startTime} AND #{endTime}

    AND lr.student_no = #{studentNo}

ORDER BY lr.late_time DESC

