UPDATE late_return
reason = #{reason}, process_status = #{processStatus}, process_result = #{processResult}, process_remark = #{processRemark}, update_time = NOW()
WHERE id = #{id}

update.foreach:
UPDATE late_return
late_return_id = #{item.lateReturnId}, student_no = #{item.studentNo}, late_time = #{item.lateTime}, reason = #{item.reason}, process_status = #{item.processStatus}, process_result = #{item.processResult}, process_remark = #{item.processRemark}, create_time = #{item.createTime}, update_time = #{item.updateTime},
WHERE id = #{item.id}

mapper.select:
SELECT
CAST(COUNT(1) AS SIGNED INTEGER) as total,
CAST(SUM(CASE WHEN lr.process_status = 'PENDING' THEN 1 ELSE 0 END) AS SIGNED INTEGER) as pending,
CAST(SUM(CASE WHEN lr.process_status = 'PROCESSING' THEN 1 ELSE 0 END) AS SIGNED INTEGER) as processing,
CAST(SUM(CASE WHEN lr.process_status = 'FINISHED' THEN 1 ELSE 0 END) AS SIGNED INTEGER) as finished
FROM late_return lr


        AND lr.late_time >= #{startLateTime}


        AND lr.late_time <= #{endLateTime}


        AND lr.student_no IN

            #{studentNo}

SELECT COUNT(*)
FROM late_return lr


        AND lr.late_time >= #{startLateTime}


        AND lr.late_time <= #{endLateTime}

    AND lr.process_status = 'FINISHED'
    AND (
        lr.process_result IS NULL
        OR lr.process_result = 'REJECTED'
    )

SELECT COUNT(DISTINCT lr.student_no)
FROM late_return lr


        AND lr.late_time >= #{startLateTime}


        AND lr.late_time <= #{endLateTime}

    AND lr.process_status = 'FINISHED'
    AND (
    lr.process_result IS NULL
    OR lr.process_result = 'REJECTED'
    )

SELECT

FROM late_return lr
LEFT JOIN student s ON lr.student_no = s.student_no


        AND lr.late_time >= #{startLateTime}


        AND lr.late_time <= #{endLateTime}


        AND s.dormitory LIKE CONCAT(#{dormitoryLike}, '%')


        AND s.college = #{college}

    AND lr.process_status = 'FINISHED'
    AND (
    lr.process_result IS NULL
    OR lr.process_result = 'REJECTED'
    )

SELECT COUNT(*)
FROM late_return lr

    lr.process_status = 'PENDING'

        AND lr.late_time >= #{startLateTime}


        AND lr.late_time <= #{endLateTime}


        AND lr.student_no IN

            #{studentNo}

SELECT COUNT(*)
FROM late_return lr

    lr.process_status = 'PROCESSING'

        AND lr.late_time >= #{startLateTime}


        AND lr.late_time <= #{endLateTime}


        AND lr.student_no IN

            #{studentNo}

SELECT COUNT(*)
FROM late_return lr

    lr.process_status = 'FINISHED'

        AND lr.late_time >= #{startLateTime}


        AND lr.late_time <= #{endLateTime}


        AND lr.student_no IN

            #{studentNo}

SELECT COUNT(*)
FROM late_return lr
WHERE lr.student_no = #{studentNo}
AND lr.late_time BETWEEN #{startLateTime} AND #{endLateTime}
AND (
    (lr.process_status = 'FINISHED' AND lr.process_result = 'REJECTED')
    OR 
    (lr.process_status = 'FINISHED' AND lr.process_result IS NULL)
)

SELECT lr.student_no as studentNo, s.name as studentName, s.college as college, s.class_name as className, COUNT(lr.id) as lateReturnCount FROM late_return lr LEFT JOIN student s ON lr.student_no = s.student_no WHERE lr.late_time BETWEEN #{startDate} AND #{endDate}
AND s.college = #{college}
AND s.class_name = #{className}
GROUP BY lr.student_no, s.name, s.college, s.class_name ORDER BY lateReturnCount DESC
